from abc import abstractmethod, ABC
from pathlib import PurePath
from typing import Dict, List, Type, Iterable

from geosat.tools.urlprotocol.local import LocalUrlProtocol
from geosat.tools.urlprotocol.urlprotocol import UrlProtocol
from .deferred_stream import DeferredStream

DEFAULT_PROTOCOLS: List[Type[UrlProtocol]] = [
    LocalUrlProtocol,
]


def _add_s3_protocol() -> None:
    from geosat.tools.urlprotocol.s3 import S3UrlProtocol

    DEFAULT_PROTOCOLS.append(S3UrlProtocol)


try:
    _add_s3_protocol()
except ImportError:
    pass


class UrlProtocols(UrlProtocol):
    """This class is responsible for handling the different types of url possible
    (S3, local, etc)

    This class takes care of forwarding the action to the right UrlProtocol handler
    """

    def __init__(
        self, protocols: Iterable[Type[UrlProtocol]] = tuple(DEFAULT_PROTOCOLS)
    ) -> None:
        super(UrlProtocols, self).__init__()
        self.protocols: Dict[str, UrlProtocol] = {
            protocol.get_scheme(): protocol() for protocol in protocols
        }

    def integrate_path(self, url: str, path: PurePath) -> str:
        return self.get_protocol(url).integrate_path(url, path)

    def extract_path(self, url: str) -> PurePath:
        return self.get_protocol(url).extract_path(url)

    def get_protocol(self, url):
        scheme = self.extract_scheme(url)
        try:
            return self.protocols[scheme]
        except KeyError as ex:
            raise ValueError(
                "Protocol not found for url '{}' with scheme '{}'".format(url, scheme)
            ) from ex

    @staticmethod
    def get_scheme():
        return "url"

    def exists(self, url: str):
        return self.get_protocol(url).exists(url)

    def list(self, url: str):
        return self.get_protocol(url).list(url)

    def request(self, url: str) -> List[str]:
        return self.get_protocol(url).request(url)

    def pull(self, url: str):
        return self.get_protocol(url).pull(url)

    def push(self, url: str):
        return self.get_protocol(url).push(url)

    def receive(self, url: str, stream):
        self.get_protocol(url).receive(url, stream)

    def send(self, url: str, stream):
        self.get_protocol(url).send(url, stream)

    def delete_cache(self, url: str) -> str:
        return self.get_protocol(url).delete_cache(url)

    def remove(self, url: str):
        self.get_protocol(url).remove(url)

    def open(self, url: str, mode: str):
        return self.get_protocol(url).open(url, mode)


class UrlContext(ABC):
    def __init__(self, url: str, url_protocol: UrlProtocol, use_strings=False):
        self.url = url
        self.url_protocol = url_protocol
        self.use_strings = use_strings

    @abstractmethod
    def __enter__(self):
        pass

    @abstractmethod
    def __exit__(self, exc_type, exc_val, exc_tb):
        pass


class UrlReader(UrlContext):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        mode = "rb" if not self.use_strings else "r"
        self.stream = self.url_protocol.open(self.url, mode=mode)

    def __enter__(self):
        return self.stream

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.stream.close()


class UrlWriter(UrlContext):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        mode = "wb" if not self.use_strings else "w"
        self.stream = self.url_protocol.open(self.url, mode=mode)

    def __enter__(self):
        return self.stream

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.stream.close()
